/**
 * Replaces marker lines and the lines disabled for one rule with placeholders.
 * Markers are parsed from the original document on every rule pass so their
 * positions remain correct even when earlier rules changed other content.
 * @param {string} text The document text
 * @param {string} placeholder The placeholder used while a rule runs
 * @param {string} ruleAlias The rule whose disabled lines are being replaced
 * @param {Set<string>} [validRuleAliases] The aliases recognized by the linter
 * @return {[string[], string]} The replaced values and placeholder text
 */
export function replaceScopedRuleIgnoreSections(text: string, placeholder: string, ruleAlias: string, validRuleAliases?: Set<string>): [string[], string] {
  const positions = getScopedRuleIgnoreSections(text, ruleAlias, validRuleAliases);
  const ascendingPositions = [...positions].sort((a, b) => a.startIndex - b.startIndex);
  const replacedValues = ascendingPositions.map((position) => text.substring(position.startIndex, position.endIndex));

  for (const position of positions) {
    text = replaceTextBetweenStartAndEndWithNewValue(text, position.startIndex, position.endIndex, placeholder);
  }

  return [replacedValues, text];
}

export function getScopedRuleIgnoreSections(text: string, ruleAlias: string, validRuleAliases?: Set<string>): {startIndex: number, endIndex: number}[] {
  const lines = getLines(text);
  const markers = getMarkers(text, lines, validRuleAliases);
  const protectedLines = new Set<number>(markers.map((marker) => marker.line));
  const disabledLines = new Set<number>();
  const scopes: Scope[] = [];
  const normalizedAlias = ruleAlias.toLowerCase();
  const markerByLine = new Map(markers.map((marker) => [marker.line, marker]));

  for (let line = 0; line < lines.length; line++) {
    const marker = markerByLine.get(line);
    if (!marker) {
      if (isDisabled(scopes, normalizedAlias)) {
        disabledLines.add(line);
      }
      continue;
    }

    switch (marker.action) {
      case 'disable':
        if (marker.rules !== null && marker.rules.length > 0) {
          scopes.push({allRules: false, rules: new Set(marker.rules), enabledRules: new Set()});
        } else if (marker.rules === null) {
          scopes.push({allRules: true, rules: new Set(), enabledRules: new Set()});
