        break;
      case 'enable':
        enableRule(scopes, marker.rules, normalizedAlias);
        break;
      case 'disable-next-line':
      case 'disable-next-n-lines':
        if (marker.rules === null || marker.rules.includes(normalizedAlias)) {
          const lineCount = marker.action === 'disable-next-line' ? 1 : marker.lineCount;
          for (let line = marker.line + 1; line < Math.min(lines.length, marker.line + 1 + lineCount); line++) {
